import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionVulnerability {

    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a website to ping: ");
            String website = reader.readLine();

            // Vulnerable code - user input is directly passed to the command line
            Process p = Runtime.getRuntime().exec("ping " + website);

            BufferedReader inputStream = new BufferedReader(new InputStreamReader(p.getInputStream()));
            String line;
            while ((line = inputStream.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

